const crypto = require('crypto');

// ══════════════════════════════════════════════════════
// CONFIGURATION
// Replace with your real Shopify webhook secret.
// Found in: Shopify Admin → Settings → Notifications → Webhooks
// DO NOT leave as placeholder in production.
// ══════════════════════════════════════════════════════
const WEBHOOK_SECRET = '__SHOPIFY_WEBHOOK_SECRET__';

// Set to true ONLY during local testing (skips HMAC check).
// MUST be false in production.
const SKIP_VERIFICATION = true;

// ── EXTRACT HEADERS ───────────────────────────────────
const first    = $input.first();
const itemJson = first.json  || {};
const binary   = first.binary || {};
const headers  = itemJson.headers || {};

// ── EXTRACT RAW BODY BYTES ────────────────────────────
// n8n delivers rawBody as binary when rawBody:true is set.
// We must get the exact bytes Shopify signed.
let rawBodyBuffer = null;

// Priority 1: binary data (most accurate)
const bd = binary.data;
if (bd && bd.data && typeof bd.data === 'string') {
  rawBodyBuffer = Buffer.from(bd.data, 'base64');
  console.log('[Webhook] body source: binary, bytes:', rawBodyBuffer.length);
}

// Priority 2: rawBody string
if (!rawBodyBuffer) {
  const rb = itemJson.rawBody;
  if (typeof rb === 'string' && rb.length > 0) {
    rawBodyBuffer = Buffer.from(rb, 'utf8');
    console.log('[Webhook] body source: rawBody string, bytes:', rawBodyBuffer.length);
  }
}

// Priority 3: body string
if (!rawBodyBuffer) {
  const bs = itemJson.body;
  if (typeof bs === 'string' && bs.length > 0) {
    rawBodyBuffer = Buffer.from(bs, 'utf8');
    console.log('[Webhook] body source: body string, bytes:', rawBodyBuffer.length);
  }
}

// Priority 4: serialise body object (last resort, may not match signature)
if (!rawBodyBuffer) {
  const bo = itemJson.body;
  if (bo && typeof bo === 'object') {
    rawBodyBuffer = Buffer.from(JSON.stringify(bo), 'utf8');
    console.log('[Webhook] body source: JSON.stringify(body), bytes:', rawBodyBuffer.length);
  }
}

if (!rawBodyBuffer || rawBodyBuffer.length === 0) {
  throw new Error('Cannot extract raw body. Ensure rawBody:true is set on the Webhook node.');
}

// ── VERIFY HMAC ───────────────────────────────────────
const provided = (
  headers['x-shopify-hmac-sha256']  ||
  headers['X-Shopify-Hmac-Sha256']  ||
  itemJson['x-shopify-hmac-sha256'] ||
  ''
).trim();

console.log('[Webhook] HMAC provided :', provided || '(none)');
console.log('[Webhook] SKIP_VERIFICATION:', SKIP_VERIFICATION);
console.log('[Webhook] Secret set:', !WEBHOOK_SECRET.startsWith('__'));

if (!SKIP_VERIFICATION) {
  if (WEBHOOK_SECRET.startsWith('__')) {
    throw new Error('Set your real Shopify webhook secret: replace __SHOPIFY_WEBHOOK_SECRET__ in the code.');
  }
  if (!provided) {
    throw new Error('Missing X-Shopify-Hmac-Sha256 header. Is this a real Shopify webhook request?');
  }
  const computed = crypto
    .createHmac('sha256', WEBHOOK_SECRET)
    .update(rawBodyBuffer)
    .digest('base64');
  console.log('[Webhook] HMAC computed  :', computed);
  // Use length-safe comparison
  const pBuf = Buffer.from(provided);
  const cBuf = Buffer.from(computed);
  const match = pBuf.length === cBuf.length &&
                crypto.timingSafeEqual(pBuf, cBuf);
  if (!match) {
    throw new Error(
      `Invalid Shopify HMAC signature.\n` +
      `  provided : ${provided}\n` +
      `  computed : ${computed}\n` +
      `  bodyBytes: ${rawBodyBuffer.length}\n` +
      `  Tip: Check your webhook secret is correct in Shopify Admin → Settings → Notifications → Webhooks`
    );
  }
  console.log('[Webhook] HMAC verified ✅');
} else {
  console.log('[Webhook] ⚠️  SKIP_VERIFICATION=true — HMAC check bypassed (testing mode)');
}

// ── PARSE PAYLOAD ─────────────────────────────────────
let payload;
try {
  payload = JSON.parse(rawBodyBuffer.toString('utf8'));
} catch (e) {
  throw new Error('Webhook body is not valid JSON: ' + e.message);
}

// ── BUILD ENVELOPE ────────────────────────────────────
const shopDomain =
  headers['x-shopify-shop-domain'] ||
  headers['X-Shopify-Shop-Domain'] ||
  'unknown-shop.myshopify.com';

const eventId =
  headers['x-shopify-webhook-id'] ||
  headers['X-Shopify-Webhook-Id']  ||
  `${payload.id || 'unknown'}-${payload.updated_at || payload.created_at || new Date().toISOString()}`;

return [{ json: {
  event_id: eventId,
  webhook_topic: 'products/create',
  envelope: {
    shop_domain: shopDomain,
    event_id: eventId,
    occurred_at: payload.created_at || payload.updated_at || new Date().toISOString(),
    payload
  }
}}];
